CREATE DATABASE IF NOT EXISTS satisfactory_tracker;

CREATE USER IF NOT EXISTS 'tracker_user'@'%' IDENTIFIED BY 'KUTcF^TI@3JBsAP6';
GRANT ALL PRIVILEGES ON satisfactory_tracker.* TO 'tracker_user'@'%';
FLUSH PRIVILEGES;

CREATE TABLE part (
    id INT PRIMARY KEY AUTO_INCREMENT,
    part_name VARCHAR(255) NOT NULL,
    level INT,
    category VARCHAR(255)    
);
CREATE TABLE recipe (
    id INT PRIMARY KEY AUTO_INCREMENT,
    part_id INT NOT NULL,
    recipe_name VARCHAR(255) NOT NULL,
    ingredient_count INT,
    source_level INT,
    base_input VARCHAR(255),
    base_production_type VARCHAR(255),
    produced_in_automated VARCHAR(255),
    produced_in_manual VARCHAR(255),
    base_demand_pm FLOAT,
    base_supply_pm FLOAT,
    byproduct VARCHAR(255),
    byproduct_supply_pm FLOAT,
    FOREIGN KEY(part_id) REFERENCES part(id)
);
CREATE TABLE alternate_recipe (
    id INT PRIMARY KEY AUTO_INCREMENT,
    part_id INT NOT NULL,
    recipe_id INT NOT NULL,
    selected INT DEFAULT 0 CHECK (selected IN (0, 1)),
    FOREIGN KEY(part_id) REFERENCES part(id),
    FOREIGN KEY(recipe_id) REFERENCES recipe(id)
);
CREATE TABLE node_purity (
    id INT PRIMARY KEY AUTO_INCREMENT,
    node_purity VARCHAR(255) NOT NULL
);
CREATE TABLE miner_type (
    id INT PRIMARY KEY AUTO_INCREMENT,
    miner_type VARCHAR(255) NOT NULL
);
CREATE TABLE miner_supply (
    id INT PRIMARY KEY AUTO_INCREMENT,
    node_purity_id INT NOT NULL,
    miner_type_id INT NOT NULL,
    base_supply_pm FLOAT NOT NULL,
    FOREIGN KEY(node_purity_id) REFERENCES node_purity(id),
    FOREIGN KEY(miner_type_id) REFERENCES miner_type(id)
);
CREATE TABLE power_shards (
    id INT PRIMARY KEY AUTO_INCREMENT,
    quantity INT NOT NULL,
    output_increase FLOAT NOT NULL
);
CREATE TABLE user (
	id INT NOT NULL, 
	username VARCHAR(150) NOT NULL, 
	role VARCHAR(100) NOT NULL, 
	email VARCHAR(150) NOT NULL, 
	password VARCHAR(200) NOT NULL, 
	is_verified BOOLEAN, 
	PRIMARY KEY (id), 
	UNIQUE (username), 
	UNIQUE (email)
);
CREATE TABLE alembic_version (
	version_num VARCHAR(32) NOT NULL, 
	CONSTRAINT alembic_version_pkc PRIMARY KEY (version_num)
);
CREATE TABLE data_validation (id INT PRIMARY KEY AUTO_INCREMENT, table_name VARCHAR(255) NOT NULL, column_name VARCHAR(255) NOT NULL, value VARCHAR(255), description VARCHAR(255));
COMMIT;
